<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  * {
    box-sizing: border-box;
  }

  body {
    font-family: Arial;
    padding: 10px;
    background: #f1f1f1;
  }
  .header h1 {
    font-size: 50px;
  }
  /* 导航条链接 */
  .topnav a {
    float: left;
    display: block;
    color: #f2f2f2;
    text-align: center;
    padding: 14px 16px;
    text-decoration: none;
  }

  /* 链接颜色修改 */
  .topnav a:hover {
    background-color: #ddd;
    color: black;
  }

  /* 创建两列 */
  /* Left column */
  .leftcolumn {
    float: left;
    width: 75%;
  }

  /* 右侧栏 */
  .rightcolumn {
    float: left;
    width: 25%;
    background-color: #f1f1f1;
    padding-left: 20px;
  }

  /* 图像部分 */
  .fakeimg {
    background-color: #DDDDDD;
    width: 100%;
    padding: 20px;
  }

  /* 文章卡片效果 */
  .card {
    border-radius: 10px;
    box-shadow: 0 2px 4px rgba(0, 0, 0, .12), 0 0 6px rgba(0, 0, 0, .04);
    background-color: white;
    padding: 20px;
    margin-top: 20px;
  }

  /* 文章标题 */
  .cardTitle {
    text-align: left;
  }

  /* 文章发布时间 */
  .cardTime {
    text-align: right;
    color: darkgray;
  }

  /* 列后面清除浮动 */
  .row:after {
    content: "";
    display: table;
    clear: both;
  }

  /* 底部 */
  .footer {
    padding: 20px;
    text-align: center;
    background: #ddd;
    margin-top: 20px;
  }

  .el-carousel__item img {
    font-size: 14px;
    opacity: 1;
    line-height: 160px;
    margin: 0;
  }

  /* 响应式布局 - 屏幕尺寸小于 800px 时，两列布局改为上下布局 */
  @media screen and (max-width: 800px) {
    .leftcolumn, .rightcolumn {
      width: 100%;
      padding: 0;
    }
  }

  /* 响应式布局 -屏幕尺寸小于 400px 时，导航等布局改为上下布局 */
  @media screen and (max-width: 400px) {
    .topnav a {
      float: none;
      width: 100%;
    }
  }
</style>



