<template>
  <div id="app">
    <!--<img src="./assets/logo.png">-->
    <div class="header">
      <h1>{{title}}</h1>
      <h2 style="float: right">editor:{{author}}</h2>
    </div>
    <div class="topnav">
      <!--导航栏-->
      <el-menu
        :default-active="activeIndex"
        class="el-menu-demo"
        mode="horizontal"
        @select="handleSelect"
        background-color="#545c64"
        text-color="#fff"
        active-text-color="#ffd04b">
        <el-menu-item index="1" @click="head()">首页</el-menu-item>
        <el-submenu index="2">
          <template slot="title" @click="open('学习目录')">学习目录</template>
          <el-menu-item index="2-1" @click="open('选项2-1')">iOS</el-menu-item>
          <el-menu-item index="2-2" @click="open('选项2-2')">Android</el-menu-item>
          <el-menu-item index="2-3" @click="open('选项2-3')">Java/服务器</el-menu-item>
          <el-menu-item index="2-4" @click="open('选项2-4')">Vue</el-menu-item>
          <el-submenu index="2-5">
            <template slot="title" @click="open('选项2-5')">选项2-5</template>
            <el-menu-item index="2-5-1" @click="open('选项2-5-1')">选项2-5-1</el-menu-item>
            <el-menu-item index="2-5-2" @click="open('选项2-5-2')">选项2-5-2</el-menu-item>
            <el-menu-item index="2-5-3" @click="open('选项2-5-3')">选项2-5-3</el-menu-item>
          </el-submenu>
        </el-submenu>
        <el-menu-item index="4" @click="about()" style="float: right">
          <p style="color: red">关注订阅号(x小铺)</p>
        </el-menu-item>
      </el-menu>
    </div>
    <router-view/>
  </div>
</template>

<script>
export default {
  name: 'App',
  data () {
    return {
      title: '加菲猫的小窝',
      author: '倪新生',
      activeIndex: '1',
      elmeun_study: [
        {
          title: 'iOS'
        },
        {
          title: 'Android'
        },
        {
          title: 'Java/服务器'
        },
        {
          item: 'Vue'
        }
      ]
    }
  },
  methods: {
    handleSelect (key, keyPath) {
      console.log(key, keyPath)
    },
    open (msg) {
      this.$alert('"' + msg + '"开发中...', '温馨提示', {
        confirmButtonText: '确定',
        callback: action => {
          this.$message({
            type: 'info',
            message: `action: ${action}`
          })
        }
      })
    },
    head () {
      this.$router.replace({
        path: '/'
      })
    },
    about () {
      this.$router.replace({
        path: './FocusMe'
      })
    }
  }
}
</script>

<style>
#app {
  font-family: 'Avenir', Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #2c3e50;
}
/* 头部标题 */
.header {
  padding: 30px;
  text-align: center;
  background: linear-gradient(to top right, #CDDC39 0%, #B1CEF7 45%, #5F9DDC 100%);
  font-family: "Xingkai SC";
}
/* 导航条 */
.topnav {
  overflow: hidden;
  background-color: #333;
}
</style>



